/**
 * AI Provider Router
 * Routes messages to appropriate providers with automatic fallback support
 * Handles provider failures, rate limits, and intelligent routing
 */

import type {
  AIProvider,
  AIModel,
  AIMessageOptions,
  AIResponse,
  ProviderRouterConfig,
} from './types';
import { ProviderError, ProviderErrorType } from './types';
import { openRouterProvider } from './openRouterProvider';
import { groqProvider } from './groqProvider';
import { huggingFaceProvider } from './huggingFaceProvider';
import { mistralProvider } from './mistralProvider';
import { geminiProvider } from './geminiProvider';
import { openaiProvider } from './openaiProvider';
import { logger } from '../logger';

const log = logger.module('ProviderRouter');
import { anthropicProvider } from './anthropicProvider';
import { xaiProvider } from './xaiProvider';
import { deepseekProvider } from './deepseekProvider';

/**
 * Fallback notification callback
 */
export type FallbackCallback = (
  failedProvider: string,
  failedModel: string,
  nextProvider: string,
  nextModel: string,
  reason: string
) => void;

/**
 * Provider registry
 */
const PROVIDERS: Record<string, AIProvider> = {
  openrouter: openRouterProvider,
  groq: groqProvider,
  huggingface: huggingFaceProvider,
  mistral: mistralProvider,
  gemini: geminiProvider,
  openai: openaiProvider,
  anthropic: anthropicProvider,
  xai: xaiProvider,
  deepseek: deepseekProvider,
};

/**
 * Default fallback order (best to worst)
 */
const DEFAULT_FALLBACK_ORDER = [
  'openrouter', // Best flexibility
  'groq', // Best speed
  'huggingface', // Free fallback
  'mistral', // European option
  'gemini', // Google fallback
];

/**
 * AI Provider Router
 * Manages provider selection and automatic fallbacks
 */
export class AIProviderRouter {
  private config: ProviderRouterConfig;
  private onFallback?: FallbackCallback;

  constructor(config: ProviderRouterConfig, onFallback?: FallbackCallback) {
    this.config = config;
    this.onFallback = onFallback;
  }

  /**
   * Update router configuration
   */
  updateConfig(config: Partial<ProviderRouterConfig>): void {
    this.config = { ...this.config, ...config };
  }

  /**
   * Get provider by ID
   */
  getProvider(providerId: string): AIProvider | null {
    return PROVIDERS[providerId] || null;
  }

  /**
   * Get all providers
   */
  getAllProviders(): Record<string, AIProvider> {
    return PROVIDERS;
  }

  /**
   * Get configured providers (those with API keys)
   */
  getConfiguredProviders(): AIProvider[] {
    return Object.values(PROVIDERS).filter((provider) => provider.isConfigured());
  }

  /**
   * Get primary provider
   */
  getPrimaryProvider(): AIProvider | null {
    return this.getProvider(this.config.primaryProvider);
  }

  /**
   * Get fallback providers in order
   */
  getFallbackProviders(): AIProvider[] {
    const fallbackOrder = this.config.fallbackOrder.length > 0
      ? this.config.fallbackOrder
      : DEFAULT_FALLBACK_ORDER;

    return fallbackOrder
      .filter((id) => id !== this.config.primaryProvider) // Exclude primary
      .map((id) => this.getProvider(id))
      .filter((provider): provider is AIProvider => provider !== null && provider.isConfigured());
  }

  /**
   * Check if a provider error is retryable with fallback
   */
  private isRetryableError(error: ProviderError): boolean {
    // Rate limits and network errors are retryable with different provider
    return (
      error.type === ProviderErrorType.RATE_LIMIT ||
      error.type === ProviderErrorType.QUOTA_EXCEEDED ||
      error.type === ProviderErrorType.NETWORK_ERROR ||
      error.type === ProviderErrorType.TIMEOUT
    );
  }

  /**
   * Send message with automatic fallback
   */
  async sendMessage(options: AIMessageOptions): Promise<AIResponse> {
    const primaryProvider = this.getPrimaryProvider();

    if (!primaryProvider) {
      throw new Error(
        `Primary provider "${this.config.primaryProvider}" not found or not configured.`
      );
    }

    // Try primary provider first
    try {
      const response = await primaryProvider.sendMessage(this.config.primaryModel, options);
      return response;
    } catch (error) {
      // If fallback is disabled, throw immediately
      if (!this.config.fallbackEnabled) {
        throw error;
      }

      // Check if error is retryable
      if (error instanceof ProviderError && this.isRetryableError(error)) {
        log.warn('Provider failed with retryable error, attempting fallback', {
          provider: error.provider,
          message: error.message
        });

        // Try fallback providers
        const fallbackProviders = this.getFallbackProviders();

        for (const fallbackProvider of fallbackProviders) {
          try {
            // Get default model for fallback provider
            const fallbackModel = fallbackProvider.getDefaultModel();

            // Notify about fallback
            if (this.config.notifyOnFallback && this.onFallback) {
              this.onFallback(
                this.config.primaryProvider,
                this.config.primaryModel,
                fallbackProvider.metadata.id,
                fallbackModel.id,
                error.message
              );
            }

            log.info('Falling back to provider', {
              provider: fallbackProvider.metadata.name,
              model: fallbackModel.name
            });

            // Try fallback provider
            const response = await fallbackProvider.sendMessage(fallbackModel.id, options);

            // Success! Return response with fallback info
            return {
              ...response,
              provider: fallbackProvider.metadata.id,
              model: fallbackModel.id,
            };
          } catch (fallbackError) {
            log.warn('Fallback provider also failed', {
              provider: fallbackProvider.metadata.name,
              error: fallbackError
            });
            // Continue to next fallback
          }
        }

        // All providers failed
        throw new Error(
          `All providers failed. Primary: ${error.message}. No working fallback found.`
        );
      }

      // Non-retryable error (invalid API key, model not found, etc.)
      throw error;
    }
  }

  /**
   * Send message to specific provider (bypass routing)
   */
  async sendMessageToProvider(
    providerId: string,
    modelId: string,
    options: AIMessageOptions
  ): Promise<AIResponse> {
    const provider = this.getProvider(providerId);

    if (!provider) {
      throw new Error(`Provider "${providerId}" not found.`);
    }

    if (!provider.isConfigured()) {
      throw new Error(`Provider "${providerId}" is not configured. Please add an API key.`);
    }

    return provider.sendMessage(modelId, options);
  }

  /**
   * Validate all configured providers
   */
  async validateProviders(): Promise<Record<string, boolean>> {
    const results: Record<string, boolean> = {};

    for (const [id, provider] of Object.entries(PROVIDERS)) {
      if (provider.isConfigured()) {
        const apiKey = provider.getApiKey();
        if (apiKey) {
          try {
            results[id] = await provider.validateApiKey(apiKey);
          } catch (error) {
            results[id] = false;
          }
        } else {
          results[id] = false;
        }
      } else {
        results[id] = false;
      }
    }

    return results;
  }

  /**
   * Provider status info
   */
  private static readonly ProviderStatusShape = {
    configured: false as boolean,
    name: '' as string,
    hasFreeModels: false as boolean,
    modelCount: 0 as number,
  };

  /**
   * Get provider status summary
   */
  getProviderStatus(): Record<string, typeof AIProviderRouter.ProviderStatusShape> {
    const status: Record<string, typeof AIProviderRouter.ProviderStatusShape> = {};

    for (const [id, provider] of Object.entries(PROVIDERS)) {
      status[id] = {
        configured: provider.isConfigured(),
        name: provider.metadata.displayName,
        hasFreeModels: provider.metadata.hasFreeModels,
        modelCount: provider.models.length,
      };
    }

    return status;
  }

  /**
   * Model with provider info
   */
  private static readonly ModelWithProviderShape = {
    providerId: '' as string,
    providerName: '' as string,
    model: {} as AIModel,
  };

  /**
   * Get all available models across all configured providers
   */
  getAllAvailableModels(): Array<typeof AIProviderRouter.ModelWithProviderShape> {
    const models: Array<typeof AIProviderRouter.ModelWithProviderShape> = [];

    for (const [id, provider] of Object.entries(PROVIDERS)) {
      if (provider.isConfigured()) {
        provider.models.forEach((model) => {
          models.push({
            providerId: id,
            providerName: provider.metadata.displayName,
            model: model,
          });
        });
      }
    }

    return models;
  }

  /**
   * Get free models across all configured providers
   */
  getFreeModels(): Array<typeof AIProviderRouter.ModelWithProviderShape> {
    return this.getAllAvailableModels().filter((item) => item.model.isFree);
  }

  /**
   * Recommend best provider for a given use case
   */
  recommendProvider(useCase: string, requireFree: boolean = false): {
    providerId: string;
    modelId: string;
  } | null {
    const configuredProviders = this.getConfiguredProviders();

    if (configuredProviders.length === 0) {
      return null;
    }

    // Filter by use case and free requirement
    for (const provider of configuredProviders) {
      const suitableModels = provider.models.filter((model) => {
        const matchesUseCase = model.useCases.includes(useCase);
        const matchesFreeRequirement = !requireFree || model.isFree;
        return matchesUseCase && matchesFreeRequirement;
      });

      if (suitableModels.length > 0) {
        // Sort by quality rating (descending)
        suitableModels.sort((a, b) => b.qualityRating - a.qualityRating);

        return {
          providerId: provider.metadata.id,
          modelId: suitableModels[0].id,
        };
      }
    }

    // No suitable model found, return default
    const defaultProvider = configuredProviders[0];
    return {
      providerId: defaultProvider.metadata.id,
      modelId: defaultProvider.getDefaultModel().id,
    };
  }
}

/**
 * Create default router instance
 */
export function createDefaultRouter(onFallback?: FallbackCallback): AIProviderRouter {
  const config: ProviderRouterConfig = {
    primaryProvider: 'openrouter',
    primaryModel: 'meta-llama/llama-3.3-70b-instruct:free',
    fallbackEnabled: true,
    fallbackOrder: DEFAULT_FALLBACK_ORDER,
    notifyOnFallback: true,
  };

  return new AIProviderRouter(config, onFallback);
}

/**
 * AI Provider Types and Interfaces
 * Defines the contract for all AI provider implementations
 */

/**
 * AI Model metadata
 */
export interface AIModel {
  id: string; // Unique model identifier (e.g., "gpt-4o", "llama-3.3-70b")
  name: string; // Display name (e.g., "GPT-4o", "Llama 3.3 70B")
  provider: string; // Provider ID (e.g., "openai", "groq")

  // Performance characteristics
  speedRating: 1 | 2 | 3 | 4 | 5; // 1 = slow, 5 = lightning fast
  qualityRating: 1 | 2 | 3 | 4 | 5; // 1 = basic, 5 = excellent

  // Capabilities
  contextWindow: number; // Max tokens in context (e.g., 128000)
  maxOutputTokens?: number; // Max tokens in response
  supportsStreaming: boolean; // Can stream responses
  supportsVision?: boolean; // Can process images
  supportsFunctionCalling?: boolean; // Can call functions

  // Cost and availability
  isFree: boolean; // Available on free tier
  costPer1MTokens?: number; // Cost in USD per 1M tokens (if paid)
  requiresApiKey: boolean; // Needs API key

  // Use cases
  useCases: string[]; // ["chat", "code", "reasoning", "creative"]
  description?: string; // Brief description of model strengths
}

/**
 * AI Provider metadata
 */
export interface AIProviderMetadata {
  id: string; // Unique provider ID (e.g., "openai", "groq")
  name: string; // Display name (e.g., "OpenAI", "Groq")
  displayName: string; // Branded name for UI
  description: string; // Brief description

  // Authentication
  requiresApiKey: boolean; // Needs API key
  apiKeyUrl?: string; // Where to get API key
  apiKeyLabel?: string; // Label for API key input (e.g., "OpenAI API Key")

  // Availability
  hasFreeModels: boolean; // Has free tier models
  freeModelIds?: string[]; // IDs of free models

  // Rate limits (free tier)
  freeTierLimits?: {
    requestsPerMinute?: number;
    requestsPerDay?: number;
    tokensPerMinute?: number;
    tokensPerDay?: number;
    description?: string; // Human-readable description
  };

  // Features
  supportsCORS?: boolean; // Can be called from browser
  requiresProxy?: boolean; // Needs backend proxy
  supportsStreaming: boolean; // Can stream responses

  // Branding
  logoUrl?: string; // Provider logo
  websiteUrl?: string; // Provider website
  docsUrl?: string; // API documentation
}

/**
 * AI message options
 */
export interface AIMessageOptions {
  prompt: string; // User message
  conversationHistory?: Array<{ role: 'user' | 'assistant' | 'system'; content: string }>; // Previous messages
  systemPrompt?: string; // System instruction
  temperature?: number; // 0-1, creativity level
  maxTokens?: number; // Max response length
  stream?: boolean; // Enable streaming
  onChunk?: (chunk: string) => void; // Stream callback
}

/**
 * AI response
 */
export interface AIResponse {
  content: string; // Response text
  model: string; // Model used
  provider: string; // Provider used
  finishReason?: 'stop' | 'length' | 'error'; // Why generation stopped
  usage?: {
    promptTokens: number;
    completionTokens: number;
    totalTokens: number;
  };
}

/**
 * Provider error types
 */
export const ProviderErrorType = {
  INVALID_API_KEY: 'invalid_api_key',
  RATE_LIMIT: 'rate_limit',
  QUOTA_EXCEEDED: 'quota_exceeded',
  MODEL_NOT_FOUND: 'model_not_found',
  NETWORK_ERROR: 'network_error',
  TIMEOUT: 'timeout',
  UNKNOWN: 'unknown',
} as const;

export type ProviderErrorType = typeof ProviderErrorType[keyof typeof ProviderErrorType];

/**
 * Provider error
 */
export class ProviderError extends Error {
  type: ProviderErrorType;
  provider: string;
  retryable: boolean;

  constructor(
    type: ProviderErrorType,
    message: string,
    provider: string,
    retryable: boolean = false
  ) {
    super(message);
    this.name = 'ProviderError';
    this.type = type;
    this.provider = provider;
    this.retryable = retryable;
  }
}

/**
 * AI Provider interface
 * All provider implementations must implement this interface
 */
export interface AIProvider {
  // Metadata
  metadata: AIProviderMetadata;
  models: AIModel[];

  // Configuration
  isConfigured(): boolean; // Has valid API key
  setApiKey(apiKey: string): void;
  getApiKey(): string | null;
  clearApiKey(): void;

  // Validation
  validateApiKey(apiKey: string): Promise<boolean>;

  // Model operations
  getModel(modelId: string): AIModel | null;
  getDefaultModel(): AIModel;
  getFreeModels(): AIModel[];

  // Messaging
  sendMessage(model: string, options: AIMessageOptions): Promise<AIResponse>;

  // Usage tracking
  getUsage?(): Promise<{ requestsToday: number; tokensToday: number; limitReached: boolean }>;
}

/**
 * Provider selection criteria
 */
export interface ProviderSelectionCriteria {
  requireFree?: boolean; // Only free models
  requireFast?: boolean; // Prioritize speed
  requireHighQuality?: boolean; // Prioritize quality
  minContextWindow?: number; // Minimum context size
  useCase?: string; // Specific use case
}

/**
 * Provider router configuration
 */
export interface ProviderRouterConfig {
  primaryProvider: string; // Primary provider ID
  primaryModel: string; // Primary model ID
  fallbackEnabled: boolean; // Enable automatic fallbacks
  fallbackOrder: string[]; // Provider IDs in fallback order
  notifyOnFallback: boolean; // Show notification when falling back
}

/**
 * Usage statistics
 */
export interface ProviderUsageStats {
  provider: string;
  model: string;
  requestsToday: number;
  tokensToday: number;
  lastRequestAt: Date | null;
  limitReached: boolean;
  resetAt?: Date; // When limits reset
}

