## Real-World Example: Categorizing Bookmarks

```typescript
import { createDefaultRouter } from '@/services/ai/providerRouter';
import { useTerminalStore } from '@/stores/useTerminalStore';

async function categorizeBookmark(
  url: string,
  title: string,
  description: string
) {
  const router = createDefaultRouter((failed, _, next, __, reason) => {
    console.warn(`Failed to use ${failed}, switching to ${next}: ${reason}`);
  });

  const store = useTerminalStore.getState();

  try {
    // Get configured providers
    const providers = router.getConfiguredProviders();
    if (providers.length === 0) {
      throw new Error('No AI providers configured. Please add an API key.');
    }

    // Send categorization request
    const response = await router.sendMessage({
      prompt: `Categorize this bookmark:
URL: ${url}
Title: ${title}
Description: ${description}

Return ONLY valid JSON: {
  "primaryCategory": "string",
  "secondaryCategories": ["string"],
  "tags": ["string"],
  "confidence": 0.0-1.0,
  "reasoning": "string"
}`,
      systemPrompt: 'You are an expert at categorizing web links into logical categories.',
      temperature: 0.2,
      maxTokens: 300,
    });

    // Parse result
    const categorization = JSON.parse(response.content);

    console.log(`Bookmark categorized using ${response.provider}/${response.model}:`, categorization);

    return categorization;

  } catch (error) {
    console.error('Categorization failed:', error);
    throw error;
  }
}
```

